BEGIN TRANSACTION;
CREATE TABLE _aggregate_meta (
                aggregate_id TEXT PRIMARY KEY,
                last_refreshed_at TEXT,
                row_count INTEGER DEFAULT 0,
                status TEXT DEFAULT 'empty'
            );
CREATE TABLE _sequences (
    sequence_name TEXT PRIMARY KEY,
    current_value INTEGER NOT NULL DEFAULT 0,
    last_reset_at TEXT DEFAULT NULL
);
CREATE TABLE ai_async_tasks (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    task_type VARCHAR(200) NOT NULL,
    session_id VARCHAR(200),
    agent_id VARCHAR(200),
    parent_task_id INTEGER,
    request TEXT NOT NULL,
    context TEXT,
    priority INTEGER DEFAULT 50,
    queue VARCHAR(200) DEFAULT 'ai_normal',
    status VARCHAR(200) DEFAULT 'pending',
    worker_id VARCHAR(200),
    started_at DATETIME,
    completed_at DATETIME,
    duration_ms INTEGER,
    result TEXT,
    error_message TEXT,
    tokens_used INTEGER,
    cost VARCHAR(200),
    model_used VARCHAR(200),
    retry_count INTEGER DEFAULT 0,
    max_retries INTEGER DEFAULT 3,
    timeout INTEGER DEFAULT 300,
    tenant_id INTEGER,
    user_id INTEGER,
    created_at DATETIME,
    updated_at DATETIME
);
CREATE TABLE annotations (
    created_at DATETIME,
    created_by VARCHAR(200),
    updated_by VARCHAR(200),
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    target_type VARCHAR(200) NOT NULL,
    target_id INTEGER NOT NULL,
    category VARCHAR(200) NOT NULL,
    content TEXT
, updated_at DATETIME, target_code VARCHAR(200), target_name VARCHAR(200), category_label VARCHAR(200));
CREATE TABLE audit_logs (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            object_type TEXT NOT NULL,
            object_id INTEGER,
            action TEXT NOT NULL,
            field_name TEXT,
            old_value TEXT,
            new_value TEXT,
            user_id TEXT,
            user_name TEXT,
            ip_address TEXT,
            user_agent TEXT,
            created_at TEXT,
            extra_data TEXT
        , log_category VARCHAR(200) NOT NULL DEFAULT 'business', log_level VARCHAR(200) NOT NULL DEFAULT 'INFO', parent_object_type VARCHAR(200), parent_object_id INTEGER, trace_id VARCHAR(200), transaction_id VARCHAR(200), status VARCHAR(200) DEFAULT 'written', status_entered_at DATETIME, retry_count INTEGER DEFAULT 0, error_message TEXT, agent_id VARCHAR(200), agent_session_id VARCHAR(200), tool_call_id VARCHAR(200), agent_reasoning TEXT);
